      end

      SH: begin
        store_data = {4{store_pre_data[15:0]}};
        store_mask = {
          {2{ cache_pkt.addr[2] &  cache_pkt.addr[1]}},
          {2{ cache_pkt.addr[2] & ~cache_pkt.addr[1]}},
          {2{~cache_pkt.addr[2] &  cache_pkt.addr[1]}},
          {2{~cache_pkt.addr[2] & ~cache_pkt.addr[1]}}
