        store_data = {8{store_pre_data[7:0]}};
        store_mask = {
           { cache_pkt.addr[2] &  cache_pkt.addr[1] &   cache_pkt.addr[0]},
           { cache_pkt.addr[2] &  cache_pkt.addr[1] &  ~cache_pkt.addr[0]},
           { cache_pkt.addr[2] & ~cache_pkt.addr[1] &   cache_pkt.addr[0]},
           { cache_pkt.addr[2] & ~cache_pkt.addr[1] &  ~cache_pkt.addr[0]},
           {~cache_pkt.addr[2] &  cache_pkt.addr[1] &   cache_pkt.addr[0]},
           {~cache_pkt.addr[2] &  cache_pkt.addr[1] &  ~cache_pkt.addr[0]},
           {~cache_pkt.addr[2] & ~cache_pkt.addr[1] &   cache_pkt.addr[0]},
           {~cache_pkt.addr[2] & ~cache_pkt.addr[1] &  ~cache_pkt.addr[0]}
        };
      end

      SM: begin
        store_data = store_pre_data;
        store_mask = cache_pkt.mask;
      end

      default: begin
        store_data = '0;
        store_mask = '0;
      end
    endcase
  end

  // load logic
  logic [7:0] byte_sel;
  logic [15:0] half_sel;
  logic [31:0] word_sel;

  assign load_data = shadow_mem[cache_pkt_word_addr];

  bsg_mux #(
    .els_p(8)
    ,.width_p(8)
